import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import API from "../api/axios";
import "../App.css";

const EditPostPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();

  const [title, setTitle] = useState("");
  const [body, setBody] = useState("");
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [updating, setUpdating] = useState(false);

  // =========================
  // FETCH EXISTING POST
  // =========================
  useEffect(() => {
    const fetchPost = async () => {
      try {
        if (!id) return;

        const res = await API.get(`/posts/${id}`); // ✅ FIXED
        const postData = res.data;

        setTitle(postData.title || "");
        setBody(postData.body || "");
        setError("");
      } catch (err) {
        console.log(err);
        setError("Post not found or you don't have permission to edit");
      } finally {
        setLoading(false);
      }
    };

    fetchPost();
  }, [id]);

  // =========================
  // UPDATE POST
  // =========================
  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setUpdating(true);

    try {
      await API.put(`/posts/${id}`, { title, body }); // ✅ FIXED

      alert("Post updated successfully!");

      // ✅ FIXED ROUTE
      navigate(`/posts/${id}`);
    } catch (err) {
      setError(err.response?.data?.message || "Failed to update post");
    } finally {
      setUpdating(false);
    }
  };

  // =========================
  // LOADING
  // =========================
  if (loading) {
    return (
      <section className="register">
        <div className="postpage-loading">Loading post...</div>
      </section>
    );
  }

  // =========================
  // ERROR
  // =========================
  if (error) {
    return (
      <section className="register">
        <div className="postpage-error">{error}</div>
        <button className="publish-btn" onClick={() => navigate(-1)}>
          Go Back
        </button>
      </section>
    );
  }

  // =========================
  // FORM
  // =========================
  return (
    <section className="register">
      <h2 className="map-caption">Edit Post #{id}</h2>

      <div className="register-content">
        <div className="register-form">
          <form onSubmit={handleSubmit} className="contact-form">
            <label htmlFor="title">Title:</label>
            <input
              id="title"
              type="text"
              placeholder="Post Title"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              required
            />

            <label htmlFor="body">Content:</label>
            <textarea
              id="body"
              placeholder="Post Content"
              rows="10"
              value={body}
              onChange={(e) => setBody(e.target.value)}
              required
            />

            {error && (
              <p className="error-msg" style={{ color: "red" }}>
                {error}
              </p>
            )}

            <button type="submit" disabled={updating} className="publish-btn">
              {updating ? "Updating..." : "Update Post"}
            </button>
          </form>
        </div>
      </div>
    </section>
  );
};

export default EditPostPage;
